const body = $('Webhook PWA').first().json.body || $('Webhook PWA').first().json;
const addr = String(body.address || '').trim() || 'Омск';
const workType = ['грузчики','уборка','стройка','разнорабочие','другое'].includes(body.work_type) ? body.work_type : 'другое';
const people = Math.max(1, Math.min(50, parseInt(body.people) || 1));
const hours = Math.max(1, Math.min(24, parseInt(body.hours) || 1));
const timeRaw = body.time || '';
const timeFormatted = timeRaw ? (() => {
  try {
    const d = new Date(timeRaw);
    if (isNaN(d.getTime())) return timeRaw;
    return d.toLocaleString('ru-RU', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
  } catch { return timeRaw; }
})() : '';

return [{ json: { address: addr, work_type: workType, people, hours, time: timeFormatted, comment: String(body.comment || '').slice(0, 1000), customer_id: body.telegram_id ? String(body.telegram_id) : 'pwa' } }];

const parsed = $('Parse PWA Body').first().json;
const geoResult = $('Nominatim Geocode').first().json;
const ratesResult = $('Read Rates').first()?.json || {};

const geo = Array.isArray(geoResult) ? geoResult[0] : geoResult;
const lat = geo?.lat ? parseFloat(geo.lat) : 54.9894;
const lon = geo?.lon ? parseFloat(geo.lon) : 73.3667;
const addr = parsed.address || 'Омск';
const yandexLink = `https://yandex.ru/maps/?pt=${lon},${lat}&z=16&text=${encodeURIComponent(addr)}`;

const people = Number(parsed.people || 1);
const hours = Number(parsed.hours || 1);
const clientRate = parseInt(ratesResult.client_rate, 10) || 600;
const workerRate = parseInt(ratesResult.worker_rate, 10) || 400;
const minHours = parseInt(ratesResult.min_hours, 10) || 1;
const effectiveHours = Math.max(hours, minHours);
const clientTotal = clientRate * people * effectiveHours;
const workerPayout = workerRate * people * effectiveHours;
const margin = clientTotal - workerPayout;
const createdAt = new Date().toISOString();

return [{
  json: {
    customer_id: parsed.customer_id,
    address: addr,
    lat,
    lon,
    yandex_link: yandexLink,
    time: parsed.time || '',
    payment_text: `${clientRate}₽/час × ${people} чел × ${effectiveHours} ч`,
    people,
    hours: effectiveHours,
    work_type: parsed.work_type || 'другое',
    comment: parsed.comment || '',
    status: 'pending',
    executor_id: '',
    message_id: '',
    created_at: createdAt,
    client_rate: clientRate,
    worker_rate: workerRate,
    client_total: clientTotal,
    worker_payout: workerPayout,
    margin,
    payout_status: 'pending',
    payout_at: ''
  }
}];
